        Task<IOBPv140GetResourceDocsOpenAPI31ApiResponse?> OBPv140GetResourceDocsOpenAPI31OrDefaultAsync(string apiversion, System.Threading.CancellationToken cancellationToken = default);

        /// <summary>
        /// Get Swagger documentation
        /// </summary>
        /// <remarks>
