        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv310UpdateMethodRoutingApiResponse"/>&gt;</returns>
        Task<IOBPv310UpdateMethodRoutingApiResponse> OBPv310UpdateMethodRoutingAsync(string methodroutingid, OBPv310CreateMethodRoutingRequest oBPv310CreateMethodRoutingRequest, System.Threading.CancellationToken cancellationToken = default);

