        /// <summary>
        /// Get Metrics &lt;p&gt;Get API metrics rows. These are records of each REST API call.&lt;/p&gt; &lt;p&gt;require CanReadMetrics role&lt;/p&gt; &lt;p&gt;&lt;strong&gt;NOTE: Automatic from_date Default&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;If you do not provide a &lt;code&gt;from_date&lt;/code&gt; parameter, this endpoint will automatically set it to:&lt;br /&gt; &lt;strong&gt;now - 9 minutes ago&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;This prevents accidentally querying all metrics since Unix Epoch and ensures reasonable response times.&lt;br /&gt; For historical/reporting queries, always explicitly specify your desired &lt;code&gt;from_date&lt;/code&gt;.&lt;/p&gt; &lt;p&gt;&lt;strong&gt;IMPORTANT: Smart Caching &amp;amp; Performance&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;This endpoint uses intelligent two-tier caching to optimize performance:&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Stable Data Cache (Long TTL):&lt;/strong&gt;&lt;br /&gt; - Metrics older than 600 seconds (10 minutes) are considered immutable/stable&lt;br /&gt; - These are cached for 86400 seconds (24 hours)&lt;br /&gt; - Used when your query&#39;s from_date is older than the stable boundary&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Recent Data Cache (Short TTL):&lt;/strong&gt;&lt;br /&gt; - Recent metrics (within the stable boundary) are cached for 7 seconds&lt;br /&gt; - Used when your query includes recent data or has no from_date&lt;/p&gt; &lt;p&gt;&lt;strong&gt;STRONGLY RECOMMENDED: Always specify from_date in your queries!&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Why from_date matters:&lt;/strong&gt;&lt;br /&gt; - Queries WITH from_date older than 10 mins → cached for 24 hours (fast!)&lt;br /&gt; - Queries WITHOUT from_date → cached for only 7 seconds (slower)&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Examples:&lt;/strong&gt;&lt;br /&gt; - &lt;code&gt;from_date&#x3D;2025-01-01T00:00:00.000Z&lt;/code&gt; → Uses 24 hours cache (historical data)&lt;br /&gt; - &lt;code&gt;from_date&#x3D;1100-01-01T01:01:01.000Z&lt;/code&gt; (recent date) → Uses 7 seconds cache (recent data)&lt;br /&gt; - No from_date → &lt;strong&gt;Automatically set to 9 minutes ago&lt;/strong&gt; → Uses 7 seconds cache (recent data)&lt;/p&gt; &lt;p&gt;For best performance on historical/reporting queries, always include a from_date parameter!&lt;/p&gt; &lt;p&gt;Filters Part 1.&lt;em&gt;filtering&lt;/em&gt; (no wilde cards etc.) parameters to GET /management/metrics&lt;/p&gt; &lt;p&gt;You can filter by the following fields by applying url parameters&lt;/p&gt; &lt;p&gt;eg: /management/metrics?from_date&#x3D;1100-01-01T01:01:01.000Z&amp;amp;to_date&#x3D;1100-01-01T01:01:01.000Z&amp;amp;limit&#x3D;50&amp;amp;offset&#x3D;2&lt;/p&gt; &lt;p&gt;1 from_date e.g.:from_date&#x3D;1100-01-01T01:01:01.000Z&lt;br /&gt; &lt;strong&gt;DEFAULT&lt;/strong&gt;: If not provided, automatically set to now - 9 minutes (keeps queries in recent data zone)&lt;br /&gt; &lt;strong&gt;IMPORTANT&lt;/strong&gt;: Including from_date enables long-term caching for historical data queries!&lt;/p&gt; &lt;p&gt;2 to_date e.g.:to_date&#x3D;1100-01-01T01:01:01.000Z Defaults to a far future date i.e. Sat Jan 01 00:00:00 UTC 4000&lt;/p&gt; &lt;p&gt;3 limit (for pagination: defaults to 50)  eg:limit&#x3D;200&lt;/p&gt; &lt;p&gt;4 offset (for pagination: zero index, defaults to 0) eg: offset&#x3D;10&lt;/p&gt; &lt;p&gt;5 sort_by (defaults to date field) eg: sort_by&#x3D;date&lt;br /&gt; possible values:&lt;br /&gt; &amp;quot;url&amp;quot;,&lt;br /&gt; &amp;quot;date&amp;quot;,&lt;br /&gt; &amp;quot;user_name&amp;quot;,&lt;br /&gt; &amp;quot;app_name&amp;quot;,&lt;br /&gt; &amp;quot;developer_email&amp;quot;,&lt;br /&gt; &amp;quot;implemented_by_partial_function&amp;quot;,&lt;br /&gt; &amp;quot;implemented_in_version&amp;quot;,&lt;br /&gt; &amp;quot;consumer_id&amp;quot;,&lt;br /&gt; &amp;quot;verb&amp;quot;&lt;/p&gt; &lt;p&gt;6 direction (defaults to date desc) eg: direction&#x3D;desc&lt;/p&gt; &lt;p&gt;eg: /management/metrics?from_date&#x3D;1100-01-01T01:01:01.000Z&amp;amp;to_date&#x3D;1100-01-01T01:01:&lt;a href&#x3D;\&quot;&amp;#109;a&amp;#105;&amp;#x6c;t&amp;#111;&amp;#58;&amp;#x30;&amp;#x31;.0&amp;#48;&amp;#x30;&amp;#x5a;&amp;#38;&amp;#x6c;&amp;#105;&amp;#109;&amp;#x69;t&amp;#61;&amp;#49;000&amp;#x30;&amp;#38;&amp;#x6f;&amp;#x66;&amp;#102;s&amp;#101;&amp;#116;&amp;#61;&amp;#x30;&amp;#x26;a&amp;#x6e;o&amp;#x6e;&amp;#61;&amp;#x66;&amp;#x61;&amp;#108;&amp;#115;&amp;#101;&amp;amp;&amp;#97;&amp;#112;&amp;#x70;_&amp;#110;&amp;#x61;&amp;#x6d;&amp;#x65;&amp;#x3d;T&amp;#101;&amp;#97;&amp;#x74;&amp;#x41;&amp;#x70;p&amp;#x26;&amp;#105;&amp;#109;&amp;#x70;&amp;#108;&amp;#101;&amp;#x6d;&amp;#101;&amp;#110;t&amp;#x65;&amp;#x64;&amp;#x5f;&amp;#105;&amp;#110;&amp;#x5f;&amp;#x76;e&amp;#x72;&amp;#115;&amp;#x69;&amp;#x6f;&amp;#x6e;&amp;#x3d;&amp;#118;2&amp;#46;&amp;#49;&amp;#x2e;&amp;#48;&amp;#38;&amp;#x76;&amp;#x65;&amp;#x72;&amp;#x62;&#x3D;&amp;#x50;O&amp;#x53;&amp;#84;&amp;#38;&amp;#117;&amp;#x73;&amp;#101;&amp;#114;&amp;#x5f;i&amp;#x64;&amp;#x3d;&amp;#x63;&amp;#x37;&amp;#x62;&amp;#x36;&amp;#99;&amp;#98;&amp;#x34;7&amp;#x2d;&amp;#x63;&amp;#x62;&amp;#57;&amp;#x36;&amp;#45;&amp;#x34;&amp;#52;&amp;#x34;1&amp;#x2d;8&amp;#x38;0&amp;#49;&amp;#45;&amp;#x33;5&amp;#98;5&amp;#55;&amp;#x34;&amp;#53;&amp;#x36;&amp;#x37;&amp;#x35;&amp;#x33;&amp;#97;&amp;#38;&amp;#117;&amp;#x73;e&amp;#114;&amp;#95;&amp;#110;&amp;#97;me&#x3D;s&amp;#117;&amp;#115;a&amp;#110;&amp;#x2e;u&amp;#107;&amp;#x2e;&amp;#x32;&amp;#x39;&amp;#64;e&amp;#120;&amp;#x61;&amp;#x6d;&amp;#x70;&amp;#108;&amp;#x65;&amp;#x2e;&amp;#x63;o&amp;#109;\&quot;&gt;&amp;#x30;&amp;#49;&amp;#46;0&amp;#48;&amp;#x30;&amp;#x5a;&amp;#38;&amp;#108;&amp;#x69;&amp;#109;&amp;#x69;&amp;#116;&amp;#61;&amp;#x31;&amp;#x30;&amp;#x30;&amp;#48;&amp;#48;&amp;#38;o&amp;#x66;f&amp;#115;&amp;#101;&amp;#x74;&#x3D;&amp;#48;&amp;#x26;&amp;#97;&amp;#110;&amp;#x6f;&amp;#x6e;&#x3D;&amp;#x66;&amp;#x61;&amp;#x6c;&amp;#115;&amp;#x65;&amp;#38;&amp;#97;p&amp;#112;&amp;#x5f;&amp;#x6e;&amp;#97;&amp;#x6d;&amp;#x65;&amp;#x3d;&amp;#